windowclass.script:
			function onInit()
				local tList = {
					sRecordType = "item",
					sSource = getDatabasePath(),
					sTitle = "Table 02-10: Standard Weapons",
					aColumns = {
						{ sName = "name", sType = "string", sHeading = "Name", nWidth=200, nSortOrder = 1 },
						{ sName = "weight_s", sType = "string", sHeading = "Wt", bCentered=true },
						{ sName = "length_s", sType = "string", sHeading = "Len", bCentered=true },
						{ sName = "fumble", sType = "number", sHeading = "Fum", nWidth=30, bCentered=true },
						{ sName = "mod1", sType = "number", sHeading = "Rng 10", sTooltip="Range Modification (10 feet)", nWidth=50, bCentered=true },
						{ sName = "mod2", sType = "number", sHeading = "Rng 25", sTooltip="Range Modification (25 feet)", nWidth=50, bCentered=true },
						{ sName = "mod3", sType = "number", sHeading = "Rng 50", sTooltip="Range Modification (50 feet)", nWidth=50, bCentered=true },
						{ sName = "mod4", sType = "number", sHeading = "Rng 100", sTooltip="Range Modification (100 feet)", nWidth=50, bCentered=true },
						{ sName = "mod5", sType = "number", sHeading = "Rng 150", sTooltip="Range Modification (150 feet)", nWidth=50, bCentered=true },
						{ sName = "attacktable.name", sType = "string", sHeading = "Table Used", nWidth=150 },
						{ sName = "at17_20", sType = "number", sHeading = "AT 17-20", sTooltip="Armor Modification (AT 17-20)", nWidth=60, bCentered=true },
						{ sName = "at13_16", sType = "number", sHeading = "AT 13-16", sTooltip="Armor Modification (AT 13-16)", nWidth=60, bCentered=true },
						{ sName = "at9_12", sType = "number", sHeading = "AT 9-12", sTooltip="Armor Modification (AT 9-12)", nWidth=60, bCentered=true },
						{ sName = "at5_8", sType = "number", sHeading = "AT 5-8", sTooltip="Armor Modification (AT 5-8)", nWidth=60, bCentered=true },
						{ sName = "at1_4", sType = "number", sHeading = "AT 1-4", sTooltip="Armor Modification (AT 1-4)", nWidth=60, bCentered=true },
					},
					aGroups = { { sDBField = "type" } },
					aGroupValueOrder = { "One-Handed Concussion", "One-Handed Slashing", "Two-Handed Weapon", "Pole Arm", "Missile Weapon", "Thrown Weapon" },
				};

				local w = Interface.openWindow("reference_groupedlist", tList.sSource);
				ListManager.initViewFromRecord(w, tList);

				close();
			end

